const updateHelmRepository = `-- name: UpdateHelmRepository :one
UPDATE helm_repositories SET
    name = $2,
    url = $3,
    repo_type = $4,
    description = $5,
    is_default = $6,
    auth_type = $7,
    auth_config = $8,
    enabled = $9
WHERE id = $1
RETURNING id, name, url, repo_type, description, is_default, auth_type, auth_config, enabled, last_synced_at, created_by_id, created_at, updated_at, owner_project_id
`

type UpdateHelmRepositoryParams struct {
	ID          uuid.UUID       `json:"id"`
	Name        string          `json:"name"`
	Url         string          `json:"url"`
	RepoType    string          `json:"repo_type"`
	Description string          `json:"description"`
	IsDefault   bool            `json:"is_default"`
	AuthType    string          `json:"auth_type"`
	AuthConfig  json.RawMessage `json:"auth_config"`
	Enabled     bool            `json:"enabled"`
}

func (q *Queries) UpdateHelmRepository(ctx context.Context, arg UpdateHelmRepositoryParams) (HelmRepository, error) {
	row := q.db.QueryRow(ctx, updateHelmRepository,
		arg.ID,
		arg.Name,
		arg.Url,
		arg.RepoType,
		arg.Description,
		arg.IsDefault,
		arg.AuthType,
		arg.AuthConfig,
		arg.Enabled,
	)
	var i HelmRepository
	err := row.Scan(
		&i.ID,
		&i.Name,
		&i.Url,
		&i.RepoType,
		&i.Description,
		&i.IsDefault,
		&i.AuthType,
		&i.AuthConfig,
		&i.Enabled,
		&i.LastSyncedAt,
		&i.CreatedByID,
		&i.CreatedAt,
		&i.UpdatedAt,
		&i.OwnerProjectID,
	)
	return i, err
}

